testFiles.content:
from config import parse_config

c = parse_config('a = 1\n# a comment\n\nb= hello \nport=8080\nname = ab cd')
assert c == {'a': 1, 'b': 'hello', 'port': 8080, 'name': 'ab cd'}, c
assert parse_config('') == {}
assert parse_config('# only comment\n\n') == {}
# value with '=' inside splits on the first '=' only
assert parse_config('url = http://x?y=1') == {'url': 'http://x?y=1'}
# digit strings become ints, non-digits stay strings
assert parse_config('x=007') == {'x': 7}
assert parse_config('x=1a') == {'x': '1a'}
try:
    parse_config('this line has no equals')
    raise SystemExit('malformed line should raise ValueError')
except ValueError:
    pass
print('ok')

