def parse_config(text):
    result = {}
    for line in text.splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        if '=' not in stripped:
            raise ValueError('missing = in line: ' + line)
        key, value = stripped.split('=', 1)
        key = key.strip()
        value = value.strip()
        if value.isdigit():
            value = int(value)
        result[key] = value
    return result
